#include <bits/stdc++.h>
using namespace std;

class Solution {
public:

    string twoSumExists(vector<int>& arr, int target) {
        int n = arr.size();

        for (int i = 0; i < n; i++) {

            for (int j = i + 1; j < n; j++) {

                if (arr[i] + arr[j] == target) {
                    return "YES";
                }
            }
        }

        return "NO";
    }

    vector<int> twoSumIndices(vector<int>& arr, int target) {
        int n = arr.size();

        for (int i = 0; i < n; i++) {

            for (int j = i + 1; j < n; j++) {

                if (arr[i] + arr[j] == target) {
                    return {i, j};
                }
            }
        }

        return {-1, -1};
    }
};

int main() {
    Solution sol;

    vector<int> arr = {2, 6, 5, 8, 11};
    int target = 14;

    cout << sol.twoSumExists(arr, target) << "\n";

    vector<int> res = sol.twoSumIndices(arr, target);
    cout << "[" << res[0] << ", " << res[1] << "]\n";

    return 0;
}

#include <bits/stdc++.h>
using namespace std;

class Solution {
public:

    string twoSumExists(vector<int>& arr, int target) {
        unordered_map<int, int> mp;
        int n = arr.size();

        for (int i = 0; i < n; i++) {
            int complement = target - arr[i];

            if (mp.find(complement) != mp.end()) {
                return "YES";
            }

            mp[arr[i]] = i;
        }

        return "NO";
    }

    vector<int> twoSumIndices(vector<int>& arr, int target) {
        unordered_map<int, int> mp;
        int n = arr.size();
        for (int i = 0; i < n; i++) {
            int complement = target - arr[i];

            if (mp.find(complement) != mp.end()) {
                return {mp[complement], i};
            }

            mp[arr[i]] = i;
        }
        return {-1, -1};
    }
};

int main() {
    Solution sol;
    vector<int> arr = {2, 6, 5, 8, 11};
    int target = 14;

    cout << sol.twoSumExists(arr, target) << "\n";
    vector<int> res = sol.twoSumIndices(arr, target);
    cout << "[" << res[0] << ", " << res[1] << "]\n";

    return 0;
}

#include <bits/stdc++.h>
using namespace std;

vector<int> twoSum(vector<int>& nums, int target) {
    vector<pair<int, int>> values;
    for (int i = 0; i < (int)nums.size(); ++i) values.push_back({nums[i], i});
    sort(values.begin(), values.end());
    int left = 0, right = (int)values.size() - 1;
    while (left < right) {
        long long sum = 1LL * values[left].first + values[right].first;
        if (sum == target) return {values[left].second, values[right].second};
        if (sum < target) ++left;
        else --right;
    }
    return {};
}

