#include <bits/stdc++.h>
using namespace std;

class Solution {
public:

    void sortZeroOneTwo(vector<int>& nums) {

        int count0 = 0, count1 = 0, count2 = 0;

        for(int i = 0; i < nums.size(); i++) {
            if(nums[i] == 0) count0++;
            else if(nums[i] == 1) count1++;
            else count2++;
        }

        int index = 0;

        while(count0--) {
            nums[index++] = 0;
        }

        while(count1--) {
            nums[index++] = 1;
        }

        while(count2--) {
            nums[index++] = 2;
        }
    }
};

int main() {
    vector<int> nums = {1, 0, 2, 1, 0};

    Solution obj;
    obj.sortZeroOneTwo(nums);

    for(int x : nums) {
        cout << x << " ";
    }

    return 0;
}

