#include <bits/stdc++.h>
using namespace std;
void nextPermutation(vector<int> &nums)
{

    int bp = -1;

    for (int i = nums.size() - 2; i >= 0; i--)
    {
        if (nums[i] < nums[i + 1])
        {
            bp = i;
            break;
        }
    }

    if (bp != -1)
    {
        for (int i = nums.size() - 1; i >= 0; i--)
        {
            if (nums[i] > nums[bp])
            {
                swap(nums[i], nums[bp]);
                break;
            }
        }
    }

    reverse(nums.begin() + bp + 1, nums.end());
}

int main() {
    cout << "Next Permutation: standalone solution is ready.\n";
    return 0;
}

