vector<int> rearrangeArray(vector<int>& nums) {
    vector<int> ans(nums.size());
    int pos = 0;
    int neg = 1;
    for (int x : nums) {
        if (x >= 0) {
            ans[pos] = x;
            pos += 2;
        } else {
            ans[neg] = x;
            neg += 2;
        }
