#include <bits/stdc++.h>
using namespace std;

class Solution {
public:

    void setZeroes(vector<vector<int>>& matrix) {

        int m = matrix.size();

        int n = matrix[0].size();

        for (int i = 0; i < m; i++) {
            for (int j = 0; j < n; j++) {

                if (matrix[i][j] == 0) {

                    for (int col = 0; col < n; col++) {
                        if (matrix[i][col] != 0)
                            matrix[i][col] = -1;
                    }

                    for (int row = 0; row < m; row++) {
                        if (matrix[row][j] != 0)
                            matrix[row][j] = -1;
                    }
                }
            }
        }

        for (int i = 0; i < m; i++) {
            for (int j = 0; j < n; j++) {
                if (matrix[i][j] == -1)
                    matrix[i][j] = 0;
            }
        }
    }
};

int main() {

    vector<vector<int>> matrix = {{1,1,1},{1,0,1},{1,1,1}};

    Solution sol;

    sol.setZeroes(matrix);

    for (auto row : matrix) {
        for (auto val : row) {
            cout << val << " ";
        }
        cout << endl;
    }
    return 0;
}

#include <bits/stdc++.h>
using namespace std;

class Solution {
public:

    void setZeroes(vector<vector<int>>& matrix) {

        int m = matrix.size();

        int n = matrix[0].size();

        vector<int> row(m, 0);

        vector<int> col(n, 0);

        for (int i = 0; i < m; i++) {
            for (int j = 0; j < n; j++) {

                if (matrix[i][j] == 0) {
                    row[i] = 1;
                    col[j] = 1;
                }
            }
        }

        for (int i = 0; i < m; i++) {
            for (int j = 0; j < n; j++) {

                if (row[i] == 1 || col[j] == 1) {
                    matrix[i][j] = 0;
                }
            }
        }
    }
};

int main() {

    vector<vector<int>> matrix = {{1,1,1},{1,0,1},{1,1,1}};

    Solution obj;

    obj.setZeroes(matrix);

    for (auto row : matrix) {
        for (auto val : row) {
            cout << val << " ";
        }
        cout << endl;
    }
    return 0;
}

#include <bits/stdc++.h>
using namespace std;

#include <vector>

void setZeroes(vector<vector<int>>& matrix) {
    int rows = matrix.size(), cols = matrix[0].size();
    bool firstCol = false;
    for (int r = 0; r < rows; ++r) {
        if (matrix[r][0] == 0) firstCol = true;
        for (int c = 1; c < cols; ++c) {
            if (matrix[r][c] == 0) matrix[r][0] = matrix[0][c] = 0;
        }
    }
    for (int r = rows - 1; r >= 0; --r) {
        for (int c = cols - 1; c >= 1; --c) {
