class Solution {
public:
    int binarySearch(int arr[], int n, int k) {
        if (arr[0] > k || arr[n-1] < k) return -1;
        int low = 0, high = n - 1, mid;
        while (low <= high)
        {
            mid = low + (high - low) / 2;
            if (arr[mid] == k)
            {
                return mid;
            }
            else if (arr[mid] > k)
            {
                high = mid-1;
            }
            else
            {
                low = mid +1 ;
            }
        }
        return -1;
    }
};
