pair<int, int> floorCeil(const vector<int>& values, int target) {
    auto lower = lower_bound(values.begin(), values.end(), target);
    int ceilValue = lower == values.end() ? -1 : *lower;
    int floorValue;
    if (lower != values.end() && *lower == target) floorValue = target;
    else if (lower == values.begin()) floorValue = -1;
    else floorValue = *prev(lower);
    return {floorValue, ceilValue};
}

