    int getDaysNeeded(const vector<int>& weights, int capacity) {
        int daysCount = 1;
        int currentLoad = 0;
        for (int w : weights) {
            if (currentLoad + w > capacity) {
                daysCount++;
                currentLoad = w;
            } else {
                currentLoad += w;
            }
        }
