        while (low <= high) {
            int mid = low + (high - low) / 2;
            if (getDaysNeeded(weights, mid) <= days) {
                ans = mid;
                high = mid - 1;
            } else {
                low = mid + 1;
            }
        }
        return ans;
    }
};

