#include <bits/stdc++.h>
using namespace std;

struct TreeNode {
    int val;
    TreeNode* left;
    TreeNode* right;
    TreeNode(int value = 0, TreeNode* leftNode = nullptr, TreeNode* rightNode = nullptr)
        : val(value), left(leftNode), right(rightNode) {}
};

void pushLeft(TreeNode* curr, stack<TreeNode*>& st) {
    while (curr) {
        st.push(curr);
        curr = curr->left;
    }
}

vector<int> inorderTraversal(TreeNode* root) {
    if (!root) {
        return {};
    }
    stack<TreeNode*> st;
    TreeNode* curr = root;
    pushLeft(curr, st);
    vector<int> ans;
    while (!st.empty()) {
        curr = st.top();
        st.pop();
        ans.push_back(curr->val);
        curr = curr->right;
        if (curr) {
            pushLeft(curr, st);
        }
    }
    return ans;
}

