#include <bits/stdc++.h>
using namespace std;

struct Node {
    int data;
    int val;
    Node* next;
    Node* prev;
    Node* left;
    Node* right;
    Node* child;
    Node* random;
    Node* bottom;
    vector<Node*> children;
    Node(int value = 0)
        : data(value), val(value), next(nullptr), prev(nullptr), left(nullptr), right(nullptr),
          child(nullptr), random(nullptr), bottom(nullptr) {}
};

vector<int> preOrder(Node* root) {
    vector<int> ans;
    Node* curr = root;

    while (curr) {
        if (!curr->left) {
            ans.push_back(curr->data);
            curr = curr->right;
        } else {
            Node* rightmost = curr->left;
            while (rightmost->right && rightmost->right != curr)
                rightmost = rightmost->right;

            if (!rightmost->right) {
                ans.push_back(curr->data);
                rightmost->right = curr;
                curr = curr->left;
            } else {
                rightmost->right = NULL;
                curr = curr->right;
            }
        }
    }

    return ans;
}

