#include <bits/stdc++.h>
using namespace std;
bool fmemo(int i, int sum, vector<int>& arr, vector<vector<int>>& dp) {
    if (sum == 0)
        return true;

    if (dp[i][sum] != -1)
        return dp[i][sum];

    if (i == 0)
        return dp[i][sum] = (sum == arr[i]);

    bool t = false;
    if (arr[i] <= sum)
        t = fmemo(i - 1, sum - arr[i], arr, dp);

    bool nt = fmemo(i - 1, sum, arr, dp);

    return dp[i][sum] = (t || nt);
}

bool ftab(int n, int tar, vector<int>& arr){
    vector<vector<int>> dp(n,vector<int>(tar+1));
    for(int i=0; i<n; i++){
        for(int sum=0; sum<=tar; sum++){
            if(sum==0){
                dp[i][sum] = true;
                continue;
            }
            if(i==0){
                dp[i][sum] = (sum==arr[i]);
                continue;
            }
            bool t = false;
            if(arr[i] <= sum) t = dp[i-1][sum-arr[i]];
            bool nt = dp[i-1][sum];
            dp[i][sum] = (t || nt);
        }
    }
    return dp[n-1][tar];
}

bool fopt(int n, int tar, vector<int>& arr){
    vector<int> prev(tar+1);
    for(int i=0; i<n; i++){
        vector<int> curr(tar+1);
        for(int sum=0; sum<=tar; sum++){
            if(sum==0){
                curr[sum] = true;
                continue;
            }
            if(i==0){
                curr[sum] = (sum==arr[i]);
                continue;
            }
            bool t = false;
            if(arr[i] <= sum) t = prev[sum-arr[i]];
            bool nt = prev[sum];
            curr[sum] = (t || nt);
        }
        prev = curr;
    }
    return prev[tar];
}

bool isSubsetSum(vector<int> arr, int sum) {
    int n = arr.size();
    vector<vector<int>> dp(n, vector<int>(sum + 1, -1));

    return fmemo(n - 1, sum, arr, dp);
}

