string findLCS(int n, int m, string &s1, string &s2) {
    vector<vector<int>> dp(n + 1, vector<int>(m + 1));
    ftab(n, m, s1, s2, dp);
    int i = n, j = m;
    string lcs = "";
    while (i > 0 && j > 0) {
        if (s1[i - 1] == s2[j - 1]) {
            lcs += s1[i - 1];
            i = i - 1;
            j = j - 1;
        } else {
            if (dp[i - 1][j] > dp[i][j - 1])
                i = i - 1;
            else
                j = j - 1;
        }
    }
    reverse(lcs.begin(), lcs.end());
    return lcs;
}

