class Solution {
public:

    int longestCommonSubstr(string str1, string str2) {
        int n = str1.size();
        int m = str2.size();

        vector<vector<int>> dp(n + 1, vector<int>(m + 1, 0));

        int ans = 0;

        for (int i = 1; i <= n; i++) {
            for (int j = 1; j <= m; j++) {

                if (str1[i - 1] == str2[j - 1]) {
                    dp[i][j] = 1 + dp[i - 1][j - 1];

                    ans = max(ans, dp[i][j]);
                } else {

                    dp[i][j] = 0;
                }
            }
        }

        return ans;
    }
};

int main() {
    string s1 = "abcjklp";
    string s2 = "acjkp";

    Solution sol;

    cout << "The Length of Longest Common Substring is " << sol.longestCommonSubstr(s1, s2) << endl;

    return 0;
}

