        if(i==n-1){return tri[i][j] ;}
        if(j > tri[i].size()){return 1e7 ;}

        int left, right ; left=right=tri[i][j] ;
        left += recursion(tri, n, i+1, j) ;
        right += recursion(tri, n, i+1, j+1) ;

        return min(left, right) ;

    }
