        if(dp[i][j] != -1){return dp[i][j] ;}

        int left, right ; left=right=tri[i][j] ;
        left += memoization(tri, n, i+1, j, dp) ;
        right += memoization(tri, n, i+1, j+1, dp) ;

        return dp[i][j] = min(left, right) ;

    }
