#include <bits/stdc++.h>
using namespace std;

class Solution {
public:

    int knapSackUtil(int ind, int W, vector<int>& wt,
                     vector<int>& val, vector<vector<int>>& dp) {

        if (ind == 0) {
            if (wt[0] <= W) return val[0];
            else return 0;
        }

        if (dp[ind][W] != -1) return dp[ind][W];

        int notTaken = knapSackUtil(ind - 1, W, wt, val, dp);

        int taken = INT_MIN;
        if (wt[ind] <= W)
            taken = val[ind] + knapSackUtil(ind - 1, W - wt[ind],
                                            wt, val, dp);

        return dp[ind][W] = max(notTaken, taken);
    }

    int knapSack(int W, vector<int>& wt, vector<int>& val, int n) {
        vector<vector<int>> dp(n, vector<int>(W + 1, -1));
        return knapSackUtil(n - 1, W, wt, val, dp);
    }
};

int main() {
    int n = 4, W = 7;
    vector<int> wt = {1, 3, 4, 5};
    vector<int> val = {1, 4, 5, 7};
    Solution obj;
    cout << obj.knapSack(W, wt, val, n) << endl;
    return 0;
}

#include <bits/stdc++.h>
using namespace std;

class Solution {
public:
    int memo (int wt[], int val[], int W, int n, int i, vector<vector<int>>&dp) {

        if(W ==0){return 0 ;}
        if(i ==n-1) {
            if(wt[i] <= W) {
                return val[i] ;
            }
            else{
                return 0 ;
            }
        }

        if(dp[i][W] != -1){return dp[i][W] ;}
        int pick(0), notPick (0) ;
        if(wt[i] <= W) {
            pick += val[i] + memo(wt, val, W-wt[i], n, i+1, dp) ;
        }
        notPick = memo(wt, val, W, n, i+1, dp) ;
        return dp[i][W] = max(pick, notPick) ;
    }
    int knapSack(int W, int wt[], int val[], int n) {
        vector<vector<int>> dp (n , vector<int>(W+1, -1)) ;
        return memo(wt, val, W, n, 0, dp) ;
    }
};

int main() {
    cout << "0/1 Knapsack: standalone solution is ready.\n";
    return 0;
}

