int fmemo(int i, int j, int n, vector<vector<int>>& tri, vector<vector<int>>& dp) {
    if (dp[i][j] != -1)
        return dp[i][j];

    if (i == n - 1)
        return dp[i][j] = tri[i][j];

    int a = fmemo(i + 1, j, n, tri, dp);
    int b = fmemo(i + 1, j + 1, n, tri, dp);
    return dp[i][j] = min(a, b) + tri[i][j];
