    for(int i=n-1; i>=0; i--){
        for(int j=i; j>=0; j--){
            if(i==n-1){
                dp[i][j] = tri[i][j];
                continue;
            }
            int a = dp[i+1][j];
            int b = dp[i+1][j+1];
            dp[i][j] = min(a,b)+tri[i][j];
        }
    }
    return dp[0][0];
}

