using namespace std;
int fmemo(int i, int val[], int W, vector<vector<int>>& dp){
    if(i == 1){
        return (W / i) * val[i - 1];
    }

    if(dp[i][W] != -1) return dp[i][W];

    int take = INT_MIN;
    if(W >= i) take = val[i - 1] + fmemo(i, val, W - i, dp);
    int notake = fmemo(i - 1, val, W, dp);

    return dp[i][W] = max(take, notake);
}

