    for(int i=1; i<n; i++){
        for(int W=0; W<=n; W++){
            if(i==1){
                dp[i][W] = (W / i) * val[i - 1];
                continue;
            }
            int take = INT_MIN;
            if(W >= i) take = val[i]+dp[i][W-i];
            int notake = dp[i-1][W];
            dp[i][W] = max(take,notake);
        }
    }
    return dp[n][n];
}

int cutRod(int price[], int N) {
    vector<vector<int>> dp(N + 1, vector<int>(N + 1, -1));
