struct ListNode {
    int val;
    ListNode* next;
    ListNode(int value = 0, ListNode* link = nullptr) : val(value), next(link) {}
};

ListNode* reverseList(ListNode* head) {
    ListNode* prev = nullptr;
    ListNode* curr = head;
    while (curr != nullptr) {
        ListNode* nextNode = curr->next;
        curr->next = prev;
        prev = curr;
        curr = nextNode;
    }
    return prev;
}

