#include <bits/stdc++.h>
using namespace std;

class Node {
public:

    int data;

    Node* next;

    Node(int data1, Node* next1) {
        data = data1;
        next = next1;
    }

    Node(int data1) {
        data = data1;
        next = nullptr;
    }
};

class Solution {
public:

    bool detectLoop(Node* head) {

        Node* temp = head;

        unordered_map<Node*, int> nodeMap;

        while (temp != nullptr) {

            if (nodeMap.find(temp) != nodeMap.end()) {
                return true;
            }

            nodeMap[temp] = 1;

            temp = temp->next;
        }

        return false;
    }
};

int main() {

    Node* head = new Node(1);
    Node* second = new Node(2);
    Node* third = new Node(3);
    Node* fourth = new Node(4);
    Node* fifth = new Node(5);

    head->next = second;
    second->next = third;
    third->next = fourth;
    fourth->next = fifth;

    fifth->next = third;

    Solution obj;

    if (obj.detectLoop(head)) {
        cout << "Loop detected in the linked list." << endl;
    } else {
        cout << "No loop detected in the linked list." << endl;
    }

    delete head;
    delete second;
    delete third;
    delete fourth;
    delete fifth;

    return 0;
}

#include <bits/stdc++.h>
using namespace std ;

struct Node{
    int data; Node* next;

    Node(int val){
        data = val; next = NULL;
    }
};

class Solution{
public:
    void removeLoop(Node* head){

        if(!head or !(head -> next)){
            return ;
        }

        Node* slow= head , *fast= head;
        while(fast != NULL and fast -> next != NULL){
            slow= slow-> next ; fast = fast -> next -> next ;

            if(slow == fast){
                break;
            }
        }

        if(slow != fast){
            return ;
        }

        slow= head ;

        if(slow == fast){

            while(fast -> next != slow){

                fast = fast -> next ;
            }
        }
        else{
            while(slow -> next != fast -> next){
                slow = slow -> next ; fast = fast-> next ;
            }
        }

        fast -> next = NULL ;
    }
};

int main() {
    cout << "Linked List Cycle Detection: standalone solution is ready.\n";
    return 0;
}

