#include <bits/stdc++.h>
using namespace std ;

struct ListNode {
    int val;
    ListNode *next;
    ListNode() : val(0), next(nullptr) {}
    ListNode(int x) : val(x), next(nullptr) {}
    ListNode(int x, ListNode *next) : val(x), next(next) {}
};

class Solution {
public:
    ListNode* reverseKGroup(ListNode* head, int k) {

        if(head == NULL or head -> next == NULL){
            return head ;
        }

        ListNode* dummy = new ListNode(-1) ; dummy ->next= head ;
        ListNode* prev , *curr , *fwd ;

        int count=1 ;
        ListNode* temp = head ;
        while(temp -> next != NULL){
            temp= temp-> next ; count++ ;
        }

        prev = dummy ;
        while(count >= k){
            curr = prev -> next ;
            fwd = curr -> next ;

            for(int i =1 ; i < k ;i++){

                curr -> next = fwd -> next ;
                fwd -> next = prev -> next ;
                prev -> next = fwd ;
                fwd = curr -> next ;
            }
            prev = curr ; count -= k ;
        }

        return dummy -> next ;

    }
};

int main() {
    cout << "Reverse in K-Group: standalone solution is ready.\n";
    return 0;
}

