using namespace std;
vector<int> dijkstra(int n, vector<vector<int>> adj[], int s){
    vector<int> dis(n, 1e9);
    priority_queue<pair<int, int>, vector<pair<int, int>>, greater<pair<int, int>>> pq;

    dis[s] = 0;
    pq.push({0, s});

    while(!pq.empty()){
        int u = pq.top().second;
        pq.pop();
        for(auto p : adj[u]){
            int v = p[0], wt = p[1];
            if(dis[u] + wt < dis[v]){
                dis[v] = dis[u] + wt;
                pq.push({dis[v], v});
            }
        }
    }

    return dis;
}

int main() {
    cout << "Dijkstra's Algorithm: standalone solution is ready.\n";
    return 0;
}

