#include <bits/stdc++.h>
using namespace std;
void topo(int node, vector<bool>& vis, vector<vector<int>>& adj, stack<int>& st) {
    vis[node] = true;
    for (auto v : adj[node]) {
        if (!vis[v]) {
            topo(v, vis, adj, st);
        }
    }
    st.push(node);
}

void dfs(int node, vector<bool>& vis, vector<int> revadj[]) {
    vis[node] = true;
    for (auto v : revadj[node]) {
        if (!vis[v]) {
            dfs(v, vis, revadj);
        }
    }
}

int kosaraju(int V, vector<vector<int>>& adj) {
    stack<int> st;
    vector<bool> vis(V);
    for (int i = 0; i < V; i++) {
        if (!vis[i])
            topo(i, vis, adj, st);
    }

    vector<int> revadj[V];
    for (int i = 0; i < V; i++) {
        for (auto j : adj[i]) {
            revadj[j].push_back(i);
        }
    }

    int ans = 0;
    vector<bool> visi(V);
    while (!st.empty()) {
        int node = st.top();
        st.pop();
        if (!visi[node]) {
            dfs(node, visi, revadj);
            ans++;
        }
    }
    return ans;
}

int main() {
    std::cout << "Kosaraju's Algorithm: standalone solution is ready.\n";
    return 0;
}

