class Solution {
public:

    bool isPrime(int n) {
        int cnt = 0;

        for (int i = 1; i * i <= n; i++) {
            if (n % i == 0) {
                cnt++;
                if (n / i != i) cnt++;
            }
        }

        return cnt == 2;
    }

    vector<int> findAllPrimes(int n) {
        vector<int> ans;

        for (int i = 2; i <= n; i++) {
            if (isPrime(i)) {
                ans.push_back(i);
            }
        }

        return ans;
    }
};

