    Solution sol;
    vector<int> primes = sol.findAllPrimes(n);

    cout << "Prime numbers less than or equal to " << n << ":\n";
    for (int prime : primes) {
        cout << prime << " ";
    }
    cout << endl;

    return 0;
}

