#include <bits/stdc++.h>
using namespace std;

vector<int> rabinKarp(const string& text, const string& pattern) {
    if (pattern.empty() || pattern.size() > text.size()) return {};
    const long long mod = 1000000007, base = 257;
    long long targetHash = 0, windowHash = 0, highest = 1;
    for (size_t i = 1; i < pattern.size(); ++i) highest = highest * base % mod;
    for (size_t i = 0; i < pattern.size(); ++i) {
        targetHash = (targetHash * base + (unsigned char)pattern[i]) % mod;
        windowHash = (windowHash * base + (unsigned char)text[i]) % mod;
    }
    vector<int> matches;
    for (size_t left = 0; left + pattern.size() <= text.size(); ++left) {
        if (windowHash == targetHash && text.compare(left, pattern.size(), pattern) == 0) {
            matches.push_back((int)left);
        }
        if (left + pattern.size() < text.size()) {
            windowHash = (windowHash - (unsigned char)text[left] * highest % mod + mod) % mod;
            windowHash = (windowHash * base + (unsigned char)text[left + pattern.size()]) % mod;
        }
    }
    return matches;
}

int main() {
    for (int index : rabinKarp("abracadabra", "abra")) cout << index << " ";
    cout << "\n";
    return 0;
}

