#include <bits/stdc++.h>
using namespace std;

class Solution {
public:

    bool isSafe(int row, int col, vector<vector<char>> &board, int n) {

        for (int j = 0; j < col; j++) {
            if (board[row][j] == 'Q') return false;
        }

        for (int i = row, j = col; i >= 0 && j >= 0; i--, j--) {
            if (board[i][j] == 'Q') return false;
        }

        for (int i = row, j = col; i < n && j >= 0; i++, j--) {
            if (board[i][j] == 'Q') return false;
        }

        return true;
    }

    void solve(int col, vector<vector<char>> &board,
               vector<vector<string>> &ans, int n) {

        if (col == n) {
            vector<string> temp;
            for (int i = 0; i < n; i++) {

                string row(board[i].begin(), board[i].end());
                temp.push_back(row);
            }
            ans.push_back(temp);
            return;
        }

        for (int row = 0; row < n; row++) {

            if (isSafe(row, col, board, n)) {

                board[row][col] = 'Q';

                solve(col + 1, board, ans, n);

                board[row][col] = '.';
            }
        }
    }

    vector<vector<string>> solveNQueens(int n) {
        vector<vector<string>> ans;

        vector<vector<char>> board(n, vector<char>(n, '.'));

        solve(0, board, ans, n);
        return ans;
    }
};

int main() {
    Solution obj;

    int n = 4;

    vector<vector<string>> res = obj.solveNQueens(n);

    for (auto &board : res) {
        for (auto &row : board) {
            cout << row << "\n";
        }
        cout << "\n";
    }

    return 0;
}

#include <bits/stdc++.h>
using namespace std;
class Solution {
public:
    vector<vector<string>> solveNQueens(int n) {
        vector<vector<string>> res; vector<string> b(n, string(n, '.'));
        vector<bool> c(n,0), d1(2*n,0), d2(2*n,0);
        dfs(0, b, res, c, d1, d2);
        return res;
    }
    void dfs(int r, vector<string>& b, vector<vector<string>>& res, vector<bool>& c, vector<bool>& d1, vector<bool>& d2) {
        if(r == b.size()) { res.push_back(b); return; }
        for(int i=0; i<b.size(); i++) {
            if(!c[i] && !d1[r+i] && !d2[r-i+b.size()]) {
                b[r][i] = 'Q'; c[i]=d1[r+i]=d2[r-i+b.size()]=1;
                dfs(r+1, b, res, c, d1, d2);
                b[r][i] = '.'; c[i]=d1[r+i]=d2[r-i+b.size()]=0;
            }
        }
    }
};

