class Solution {
public:
    bool exist(vector<vector<char>>& b, string w) {
        for(int i=0; i<b.size(); i++) for(int j=0; j<b[0].size(); j++) if(dfs(b, w, i, j, 0)) return true;
        return false;
    }
    bool dfs(vector<vector<char>>& b, string& w, int r, int c, int i) {
        if(i == w.size()) return true;
        if(r<0||c<0||r>=b.size()||c>=b[0].size()||b[r][c]!=w[i]) return false;
        char t = b[r][c]; b[r][c] = '#';
        bool res = dfs(b,w,r+1,c,i+1)||dfs(b,w,r-1,c,i+1)||dfs(b,w,r,c+1,i+1)||dfs(b,w,r,c-1,i+1);
        b[r][c] = t; return res;
    }
};

