    TreeNode* right;
    TreeNode(int value = 0, TreeNode* leftNode = nullptr, TreeNode* rightNode = nullptr)
        : val(value), left(leftNode), right(rightNode) {}
};

void inorder(TreeNode* root, int k, int& cnt, int& ans) {
    if (!root) return;
    inorder(root->left, k, cnt, ans);
    cnt++;
    if (cnt == k) {
        ans = root->val;
        return;
    }
    inorder(root->right, k, cnt, ans);
}

int kthSmallest(TreeNode* root, int k) {
    int ans = -1, cnt = 0;
    inorder(root, k, cnt, ans);
