#include <bits/stdc++.h>
using namespace std;

struct Node
{
    int data;
    struct Node *left;
    struct Node *right;

    Node(int x)
    {
        data = x;
        left = right = NULL;
    }
};

Node* getMini (Node* root) {

    while(root) {

        if(root -> left) {
            root = root -> left ;
        }
        else {
            return root ;
        }
    }
}

Node *deleteNode(Node *root, int x) {

    if(root == NULL) {return root ;}

    if(root -> data == x) {

        if(!(root -> left)and !(root -> right)) {
            delete root ;
            return NULL ;
        }

        if(root -> left and !(root -> right)) {
            Node* temp =root -> left ; delete(root) ;
            return temp ;
        }
        else if(root -> right and !(root ->left)) {
            Node* temp = root -> right ; delete(root) ;
            return temp ;
        }

        else{
            int newVal = getMini (root-> right) ->data ;
            root -> data = newVal ;
            root ->right = deleteNode(root ->right, newVal) ;
            return root ;
        }

    }
    else if (root -> data > x) {
        root -> left = deleteNode(root -> left, x) ;
        return root ;
    }
    else{
        root -> right = deleteNode(root -> right, x) ;
        return root;
    }
}

int main() {
    cout << "Delete Node in a BST: standalone solution is ready.\n";
    return 0;
}

