struct Job {
    int id;
    int deadline;
    int profit;
};

pair<int, int> scheduleJobs(vector<Job> jobs) {
    sort(jobs.begin(), jobs.end(), [](const Job& left, const Job& right) {
        return left.profit > right.profit;
    });
    int lastSlot = 0;
    for (const Job& job : jobs) lastSlot = max(lastSlot, job.deadline);
    vector<int> slots(lastSlot + 1, -1);
    int count = 0, profit = 0;
    for (const Job& job : jobs) {
        for (int slot = min(lastSlot, job.deadline); slot > 0; --slot) {
            if (slots[slot] == -1) {
                slots[slot] = job.id;
                ++count;
                profit += job.profit;
                break;
            }
        }
    }
    return {count, profit};
}

int main() {
    vector<Job> jobs = {{1, 2, 100}, {2, 1, 19}, {3, 2, 27}, {4, 1, 25}, {5, 3, 15}};
    auto answer = scheduleJobs(jobs);
    cout << answer.first << " " << answer.second << "\n";
    return 0;
}

