        TrieNode* curr = root;
        for(char c : word) {
            int index = c - 'a';
            if(curr->children[index] == nullptr) return false;
            curr = curr->children[index];
        }
        return curr->isEndOfWord;
    }

    bool startsWith(string prefix) {
        TrieNode* curr = root;
        for(char c : prefix) {
            int index = c - 'a';
            if(curr->children[index] == nullptr) return false;
            curr = curr->children[index];
        }
        return true;
    }
};

