#include <bits/stdc++.h>
using namespace std;

class Solution {
public:

    bool dfs(vector<vector<char>>& board, string& word, int index, int row, int col, vector<vector<bool>>& visited) {

        if (index == word.size())
            return true;

        if (row < 0 || col < 0 || row >= board.size() || col >= board[0].size() || visited[row][col] || board[row][col] != word[index])
            return false;

        visited[row][col] = true;

        bool down = dfs(board, word, index + 1, row + 1, col, visited);

        bool up = dfs(board, word, index + 1, row - 1, col, visited);

        bool right = dfs(board, word, index + 1, row, col + 1, visited);

        bool left = dfs(board, word, index + 1, row, col - 1, visited);

        bool found = down || up || right || left;

        visited[row][col] = false;

        return found;
    }

    vector<string> findWords(vector<vector<char>>& board, vector<string>& words) {

        vector<string> result;

        int rows = board.size();

        int cols = board[0].size();

        for (string& word : words) {

            bool wordFound = false;

            vector<vector<bool>> visited(rows, vector<bool>(cols, false));

            for (int r = 0; r < rows && !wordFound; r++) {
                for (int c = 0; c < cols && !wordFound; c++) {

                    if (dfs(board, word, 0, r, c, visited)) {

                        result.push_back(word);

                        wordFound = true;
                    }
                }
            }
        }

        return result;
    }
};

int main() {

    vector<vector<char>> board = {
        {'b','a','d','a','m'},
        {'x','y','g','l','a'},
        {'o','m','o','m','o'}
    };

    vector<string> words = {"mom", "elephant", "bob", "badam", "glad"};

    Solution sol;

    vector<string> foundWords = sol.findWords(board, words);

    cout << "[";
    for (int i = 0; i < foundWords.size(); i++) {
        cout << "\"" << foundWords[i] << "\"";
        if (i < foundWords.size() - 1) cout << ", ";
    }
    cout << "]" << endl;
}

#include <bits/stdc++.h>
using namespace std;

struct TrieNode {
    array<TrieNode*, 26> next{};
    string word;
};

void insertWord(TrieNode* root, const string& word) {
    for (char character : word) {
        int index = character - 'a';
        if (!root->next[index]) root->next[index] = new TrieNode();
        root = root->next[index];
    }
    root->word = word;
}

void searchBoard(vector<vector<char>>& board, int row, int col, TrieNode* node, vector<string>& found) {
    char character = board[row][col];
    if (character == '#' || !node->next[character - 'a']) return;
    node = node->next[character - 'a'];
    if (!node->word.empty()) {
        found.push_back(node->word);
        node->word.clear();
    }
    board[row][col] = '#';
    const int directions[5] = {1, 0, -1, 0, 1};
    for (int direction = 0; direction < 4; ++direction) {
        int nextRow = row + directions[direction];
        int nextCol = col + directions[direction + 1];
        if (nextRow >= 0 && nextRow < (int)board.size() && nextCol >= 0 && nextCol < (int)board[0].size()) {
            searchBoard(board, nextRow, nextCol, node, found);
        }
    }
    board[row][col] = character;
}

vector<string> findWords(vector<vector<char>> board, const vector<string>& words) {
    TrieNode* root = new TrieNode();
    for (const string& word : words) insertWord(root, word);
    vector<string> found;
    for (int row = 0; row < (int)board.size(); ++row) {
        for (int col = 0; col < (int)board[0].size(); ++col) searchBoard(board, row, col, root, found);
    }
    return found;
}

int main() {
    vector<vector<char>> board = {{'o','a','a','n'}, {'e','t','a','e'}, {'i','h','k','r'}, {'i','f','l','v'}};
    for (const string& word : findWords(board, {"oath", "pea", "eat", "rain"})) cout << word << " ";
    cout << "\n";
    return 0;
}

