    TrieNode* child[26];

    TrieNode() {
        this->cntPre = 0;
        this->cntWord = 0;
        for (int i = 0; i < 26; i++) {
            this->child[i] = NULL;
        }
    }
};

class Trie {
public:
    TrieNode* root;

    Trie() {
        root = new TrieNode();
    }

    void insert(string &word) {
        TrieNode* curr = root;
        for (int i = 0; i < word.size(); i++) {
            int ltr = word[i] - 'a';
            if (!curr->child[ltr])
                curr->child[ltr] = new TrieNode();
            curr = curr->child[ltr];
            curr->cntPre++;
        }
        curr->cntWord++;
    }

    int countWordsEqualTo(string &word) {
        TrieNode* curr = root;
        for (int i = 0; i < word.size(); i++) {
            int ltr = word[i] - 'a';
            if (!curr->child[ltr])
                return 0;
            curr = curr->child[ltr];
        }
        return curr->cntWord;
    }

    int countWordsStartingWith(string &prefix) {
        TrieNode* curr = root;
        for (int i = 0; i < prefix.size(); i++) {
            int ltr = prefix[i] - 'a';
            if (!curr->child[ltr])
                return 0;
            curr = curr->child[ltr];
        }
        return curr->cntPre;
    }

    void erase(string &word) {
        TrieNode* curr = root;
        for (int i = 0; i < word.size(); i++) {
            int ltr = word[i] - 'a';
            curr = curr->child[ltr];
            curr->cntPre--;
        }
        curr->cntWord--;
    }
};

