#include <bits/stdc++.h>
using namespace std;

class Node {
public:
    int key , val , freq ; Node *prev, *next ;
    Node (int key, int val) {
        this -> key = key; this -> val = val;
        this -> prev = NULL ; this -> next = NULL ;
        this -> freq =1 ;
    }
};

class List {
public:
    Node *head, *tail; int size ;
    List () {
        head = new Node (-1, -1) ; tail = new Node(-1, -1) ;
        head -> next = tail ; tail -> prev = head ; size = 0;
    }

    void add (Node *node) {

        node -> next = head -> next ;
        head -> next -> prev = node ;
        head -> next = node ; node -> prev = head ;
        size++ ;
    }

    void remove (Node *node) {
        node -> prev -> next = node -> next ;
        node -> next -> prev = node -> prev ;
        delete(node) ; --size ;
    }
};

class LFUCache {
public:
    map<int, List*> mpp1 ; map<int, Node*> mpp2 ;
    int capacity , minFreq , currSize ;
    LFUCache(int capacity) {
        this -> capacity = capacity ;
        this -> minFreq = 0 ; this -> currSize = 0 ;
    }

    void update (Node* node) {

        mpp2.erase(node->key) ;

        mpp1[node->freq]->remove(node) ;

        if(node -> freq == minFreq and mpp1[node -> freq]->size==0) {
            minFreq++ ;
        }

        List* nextHigherFreq = new List() ;
        if(mpp1.count((node->freq) +1)) {
            nextHigherFreq = mpp1[(node -> freq) +1];
        }

        node -> freq += 1;
        nextHigherFreq-> add(node) ;
        mpp1[node -> freq] = nextHigherFreq ;
        mpp2[node->key] = node ;
    }

    int get(int key) {
        if(mpp2.count(key)){

            Node* node = mpp2[key] ; int val = node -> val ;
            update(node) ;
            return val;
        }
        else{
            return -1 ;
        }
    }

    void put(int key, int value) {

        if(capacity ==0){return ;}

        if(mpp2.count(key)) {

            Node* node = mpp2[key] ;
            node -> val = value;
            update(node) ;
        }
        else{

            if(currSize == capacity) {

                List *list = mpp1[minFreq] ;
                mpp2.erase(list -> tail -> prev -> key) ;
                mpp1[minFreq]->remove(list -> tail -> prev) ;
                currSize -=1 ;
            }
            currSize +=1 ; minFreq =1 ;

            List *list1 = new List() ;
            if(mpp1.count(minFreq)) {
                list1 = mpp1[minFreq] ;
            }

            Node* node = new Node(key, value) ;
            list1 -> add(node) ;
            mpp2[key] = node ;
            mpp1[minFreq] = list1 ;
        }
    }
};

int main() {
    cout << "LFU Cache: standalone solution is ready.\n";
    return 0;
}

