    vector<int> maxSlidingWindow(vector<int>& nums, int k) {

        vector<int> result;

        for (int i = 0; i <= nums.size() - k; i++) {

            int maxVal = nums[i];

            for (int j = i; j < i + k; j++) {

                maxVal = max(maxVal, nums[j]);
