class Solution{
public:
    int wordLadderLength(string startWord, string targetWord, vector<string> &wordList){

        int n = startWord.length() ;

        unordered_set<string> st ;
        for(auto it : wordList){
            st.insert(it) ;
        }

        queue<pair<string, int>> q ;
        q.push({startWord, 0}) ;

        while(!q.empty()){
            auto it = q.front() ; q.pop() ;
            string curr = it.first ; int count = it.second ;
            if(curr == targetWord){
                return count+ 1;
            }

            for(int i=0; i< n ; i++){
                int original = curr[i] ;
                for(char k = 'a' ; k <= 'z' ; k++){
                    curr[i] = k ;
                    if(st.count(curr)){
                        q.push({curr, count+1}) ;
                        st.erase(curr) ;
                    }
                }
                curr[i]= original ;
            }
        }

        return 0 ;

    }
};

