#include <bits/stdc++.h>
using namespace std;
int divideTwoInteger(int dividend, int divisor) {
    if (dividend == divisor)
        return 1;

    bool isNegative = ((dividend < 0 && divisor >= 0) || (dividend >= 0 && divisor < 0));

    int ans = 0;
    int a = abs(dividend);
    int b = abs(divisor);

    while (a >= b) {

        int q = 1;
        while (a > (b << q))
            q++;
        ans += (1 << (q - 1));
        a -= (b << (q - 1));
    }

    return (isNegative) ? -ans : ans;
}

int main() {
