disjoint-set-union-by-rank-size.code:
#include <bits/stdc++.h>
using namespace std;

class DisjointSet {
    vector<int> parent;
    vector<int> rank;
    vector<int> size;
public:
    explicit DisjointSet(int count) : parent(count), rank(count), size(count, 1) {
        iota(parent.begin(), parent.end(), 0);
    }
    int find(int node) {
        return parent[node] == node ? node : parent[node] = find(parent[node]);
    }
    bool uniteByRank(int left, int right) {
        left = find(left);
        right = find(right);
        if (left == right) return false;
        if (rank[left] < rank[right]) swap(left, right);
        parent[right] = left;
        if (rank[left] == rank[right]) ++rank[left];
        size[left] += size[right];
        return true;
    }
    int componentSize(int node) {
        return size[find(node)];
    }
};

int main() {
    DisjointSet sets(5);
    sets.uniteByRank(0, 1);
    sets.uniteByRank(1, 2);
    cout << sets.componentSize(0) << "\n";
    return 0;
}

segment-tree-point-update-range-query.code:
#include <bits/stdc++.h>
using namespace std;

class SegmentTree {
    int size;
    vector<long long> tree;
public:
    explicit SegmentTree(const vector<int>& values) {
        size = 1;
        while (size < (int)values.size()) size *= 2;
        tree.assign(2 * size, 0);
        for (int index = 0; index < (int)values.size(); ++index) tree[size + index] = values[index];
        for (int node = size - 1; node > 0; --node) tree[node] = tree[2 * node] + tree[2 * node + 1];
    }
    void update(int index, int value) {
        int node = size + index;
        tree[node] = value;
        while ((node /= 2) > 0) tree[node] = tree[2 * node] + tree[2 * node + 1];
    }
    long long query(int left, int right) const {
        long long answer = 0;
        for (left += size, right += size; left <= right; left /= 2, right /= 2) {
            if (left % 2 == 1) answer += tree[left++];
            if (right % 2 == 0) answer += tree[right--];
        }
        return answer;
    }
};

int main() {
    SegmentTree tree({1, 3, 5, 7, 9});
    cout << tree.query(1, 3) << "\n";
    tree.update(2, 6);
    cout << tree.query(1, 3) << "\n";
    return 0;
}

fenwick-tree-binary-indexed-tree.code:
#include <bits/stdc++.h>
using namespace std;

class FenwickTree {
    vector<long long> tree;
public:
    explicit FenwickTree(int size) : tree(size + 1, 0) {}
    void add(int index, int delta) {
        for (++index; index < (int)tree.size(); index += index & -index) tree[index] += delta;
    }
    long long prefixSum(int index) const {
        long long answer = 0;
        for (++index; index > 0; index -= index & -index) answer += tree[index];
        return answer;
    }
    long long rangeSum(int left, int right) const {
        return prefixSum(right) - (left ? prefixSum(left - 1) : 0);
    }
};

int main() {
    FenwickTree tree(5);
    for (int index = 0; index < 5; ++index) tree.add(index, index + 1);
    cout << tree.rangeSum(1, 3) << "\n";
    return 0;
}

