#include <bits/stdc++.h>
using namespace std;

void printPattern(int id, int size) {
    for (int row = 1; row <= size; ++row) {
        string line;
        for (int col = 1; col <= size; ++col) {
            bool border = row == 1 || col == 1 || row == size || col == size;
            switch (id) {
                case 1: line += '*'; break;
                case 2: line += col <= row ? '*' : ' '; break;
                case 3: line += col <= row ? char('0' + col % 10) : ' '; break;
                case 4: line += col <= row ? char('0' + row % 10) : ' '; break;
                case 5: line += col <= size - row + 1 ? '*' : ' '; break;
                case 6: line += col <= size - row + 1 ? char('0' + col % 10) : ' '; break;
                case 7: line += abs(col - (size + 1) / 2) < row ? '*' : ' '; break;
                case 8: line += abs(col - (size + 1) / 2) < size - row + 1 ? '*' : ' '; break;
                case 9: line += row <= (size + 1) / 2 ? (col <= row ? '*' : ' ') : (col <= size - row + 1 ? '*' : ' '); break;
                case 10: line += col <= min(row, size - row + 1) ? '*' : ' '; break;
                case 11: line += col <= row ? char('0' + ((row + col) % 2)) : ' '; break;
                case 12: line += col == row || col == size - row + 1 ? '*' : ' '; break;
                case 13: line += col <= row ? char('A' + (row + col - 2) % 26) : ' '; break;
                case 14: line += col <= size - row + 1 ? char('A' + col - 1) : ' '; break;
                case 15: line += col <= row ? char('A' + row - 1) : ' '; break;
                case 16: line += col <= row ? char('A' + col - 1) : ' '; break;
                case 17: line += abs(col - (size + 1) / 2) < row ? char('A' + min(col - 1, size - col)) : ' '; break;
                case 18: line += col <= row ? char('A' + size - col) : ' '; break;
                case 19: line += col <= size - row + 1 || col > row - 1 ? '*' : ' '; break;
                case 20: line += col <= row || col > size - row ? '*' : ' '; break;
                case 21: line += border ? '*' : ' '; break;
                default: line += char('0' + max({row, col, size - row + 1, size - col + 1}) % 10);
            }
        }
        cout << line << "\n";
    }
}

int main() {
    for (int id = 1; id <= 22; ++id) {
        cout << "Pattern " << id << "\n";
        printPattern(id, 5);
    }
    return 0;
}

