pair<int, int> highestLowestFrequency(const vector<int>& values) {
    unordered_map<int, int> frequency;
    for (int value : values) ++frequency[value];
    int highest = values.front(), lowest = values.front();
    for (const auto& entry : frequency) {
        int value = entry.first;
        int count = entry.second;
        if (count > frequency[highest] || (count == frequency[highest] && value < highest)) highest = value;
        if (count < frequency[lowest] || (count == frequency[lowest] && value < lowest)) lowest = value;
    }
