int findMin(const vector<int>& nums) {
    if (nums.empty()) {
        return INT_MIN;
    }

    int low = 0;
    int high = static_cast<int>(nums.size()) - 1;
    int ans = INT_MAX;

    while (low <= high) {
        if (nums[low] <= nums[high]) {
            ans = min(ans, nums[low]);
            break;
        }

        int mid = low + (high - low) / 2;

        if (nums[low] <= nums[mid]) {
            ans = min(ans, nums[low]);
            low = mid + 1;
        } else {
            ans = min(ans, nums[mid]);
            high = mid - 1;
        }
    }

    return ans;
}

