    int low = 1, high = m;
    while (low <= high) {
        int mid = low + (high - low) / 2;
        int state = getPowerState(mid, n, m);
        if (state == 1) return mid;
        if (state == 0) low = mid + 1;
        else high = mid - 1;
    }
    return -1;
}

