#include <bits/stdc++.h>
using namespace std;

struct Node {
    int data;
    int val;
    Node* next;
    Node* prev;
    Node* left;
    Node* right;
    Node* child;
    Node* random;
    Node* bottom;
    vector<Node*> children;
    Node(int value = 0)
        : data(value), val(value), next(nullptr), prev(nullptr), left(nullptr), right(nullptr),
          child(nullptr), random(nullptr), bottom(nullptr) {}
};

class Solution {
public:
    Node* reverse(Node* head) {
        Node *prev = NULL, *curr = head;
        while(curr) {
            Node* nxt = curr->next;
            curr->next = prev;
            prev = curr;
            curr = nxt;
        }
        return prev;
    }

    Node* reverseKGroup(Node* head, int k) {
        Node* temp = head;
        for(int i=0; i<k-1 && temp; i++) temp = temp->next;
        if(!temp) return head;

        Node* nextNode = temp->next;
        temp->next = NULL;
        Node* newHead = reverse(head);
        head->next = reverseKGroup(nextNode, k);
        return newHead;
    }
};

