    head->next = new ListNode(2);
    head->next->next = new ListNode(3);
    head->next->next->next = new ListNode(4);
    head->next->next->next->next = new ListNode(5);

    Solution obj;
    int k = 2;
    ListNode* result = obj.rotateRight(head, k);

    while (result) {
        cout << result->val << " ";
        result = result->next;
    }
    return 0;
}

#include <bits/stdc++.h>
using namespace std;

struct Node {
    int data;
    int val;
    Node* next;
    Node* prev;
    Node* left;
    Node* right;
    Node* child;
    Node* random;
    Node* bottom;
    vector<Node*> children;
    Node(int value = 0)
        : data(value), val(value), next(nullptr), prev(nullptr), left(nullptr), right(nullptr),
          child(nullptr), random(nullptr), bottom(nullptr) {}
};

class Solution {
public:
    Node* rotateRight(Node* head, int k) {
        if(!head || !head->next || k == 0) return head;
        Node* tail = head;
        int l = 1;
        while(tail->next) { l++; tail = tail->next; }
        k %= l;
        if(k == 0) return head;
        tail->next = head;
        Node* nt = head;
        for(int i=0; i<l-k-1; i++) nt = nt->next;
        Node* nh = nt->next;
        nt->next = NULL;
        return nh;
    }
};

