#include <bits/stdc++.h>
using namespace std;

class LinkedQueue {
    struct Node {
        int value;
        Node* next;
        Node(int item) : value(item), next(nullptr) {}
    };
    Node* frontNode = nullptr;
    Node* backNode = nullptr;
public:
    ~LinkedQueue() {
        while (!empty()) pop();
    }
    void push(int value) {
        Node* node = new Node(value);
        if (backNode) backNode->next = node;
        else frontNode = node;
        backNode = node;
    }
    int pop() {
        if (empty()) throw underflow_error("empty queue");
        Node* node = frontNode;
        int value = node->value;
        frontNode = frontNode->next;
        if (!frontNode) backNode = nullptr;
        delete node;
        return value;
    }
    bool empty() const {
        return frontNode == nullptr;
    }
};

int main() {
    LinkedQueue queue;
    queue.push(10);
    queue.push(20);
    cout << queue.pop() << " " << queue.pop() << "\n";
