#include <bits/stdc++.h>
using namespace std;
class Solution {
public:
    int prec(char c) {
        if(c == '^') return 3;
        if(c == '*' || c == '/') return 2;
        if(c == '+' || c == '-') return 1;
        return -1;
    }
    string infixToPostfix(string s) {
        string res = ""; stack<char> st;
        for(char c : s) {
            if(isalnum(c)) res += c;
            else if(c == '(') st.push(c);
            else if(c == ')') {
                while(!st.empty() && st.top() != '(') { res += st.top(); st.pop(); }
                st.pop();
            } else {
                while(!st.empty() && prec(c) <= prec(st.top())) {
                    res += st.top(); st.pop();
                }
                st.push(c);
            }
        }
        while(!st.empty()) { res += st.top(); st.pop(); }
        return res;
    }
};

