#include <bits/stdc++.h>
using namespace std;

class Solution {
public:

    int trap(vector<int>& height) {
        int n = height.size();

        int totalWater = 0;

        for (int i = 0; i < n; i++) {

            int maxLeft = 0;
            int maxRight = 0;

            for (int j = 0; j <= i; j++) {
                if (height[j] > maxLeft) {
                    maxLeft = height[j];
                }
            }

            for (int j = i; j < n; j++) {
                if (height[j] > maxRight) {
                    maxRight = height[j];
                }
            }

            totalWater += min(maxLeft, maxRight) - height[i];
        }

        return totalWater;
    }
};

int main() {

    vector<int> height = {0,1,0,2,1,0,1,3,2,1,2,1};

    Solution sol;

    int result = sol.trap(height);

    cout << "Trapped Rainwater: " << result << endl;

    return 0;
}

