#include <bits/stdc++.h>
using namespace std;

string minimumWindowSubsequence(const string& source, const string& target) {
    int bestStart = -1, bestLength = numeric_limits<int>::max();
    for (int start = 0; start < (int)source.size(); ++start) {
        if (source[start] != target[0]) continue;
        int sourceIndex = start, targetIndex = 0;
        while (sourceIndex < (int)source.size() && targetIndex < (int)target.size()) {
            if (source[sourceIndex] == target[targetIndex]) ++targetIndex;
            ++sourceIndex;
        }
        if (targetIndex != (int)target.size()) break;
        int end = sourceIndex - 1;
        targetIndex = (int)target.size() - 1;
        while (end >= start) {
            if (source[end] == target[targetIndex] && --targetIndex < 0) break;
            --end;
        }
        if (sourceIndex - end < bestLength) {
            bestStart = end;
            bestLength = sourceIndex - end;
        }
        start = end;
    }
    return bestStart < 0 ? "" : source.substr(bestStart, bestLength);
}

int main() {
    cout << minimumWindowSubsequence("abcdebdde", "bde") << "\n";
    return 0;
}

