struct TreeNode {
    int val;
    TreeNode* left;
    TreeNode* right;
    TreeNode(int value) : val(value), left(nullptr), right(nullptr) {}
};

array<vector<int>, 3> allTraversals(TreeNode* root) {
    array<vector<int>, 3> answer;
    if (!root) return answer;
    stack<pair<TreeNode*, int>> work;
    work.push({root, 1});
    while (!work.empty()) {
        pair<TreeNode*, int> current = work.top();
        work.pop();
        TreeNode* node = current.first;
        int state = current.second;
        if (state == 1) {
            answer[0].push_back(node->val);
            work.push({node, 2});
            if (node->left) work.push({node->left, 1});
        } else if (state == 2) {
            answer[1].push_back(node->val);
            work.push({node, 3});
            if (node->right) work.push({node->right, 1});
        } else {
            answer[2].push_back(node->val);
        }
    }
    return answer;
}

int main() {
    TreeNode* root = new TreeNode(1);
    root->left = new TreeNode(2);
    root->right = new TreeNode(3);
    for (const auto& traversal : allTraversals(root)) {
