            auto p = q.front();
            q.pop();
            TreeNode* curr = p.second;
            int hd = p.first;
            if (curr->left) {
                mini = min(mini, hd - 1);
                q.push({hd - 1, curr->left});
            }
            if (curr->right) {
                maxi = max(maxi, hd + 1);
                q.push({hd + 1, curr->right});
            }
            mp[hd].push_back({lvl, curr->val});
        }
        lvl++;
    }

    vector<vector<int>> ans;
    for (int i = mini; i <= maxi; i++) {
        sort(mp[i].begin(), mp[i].end());
        vector<int> temp;
        for (auto it : mp[i])
            temp.push_back(it.second);
        ans.push_back(temp);
    }

    return ans;
}

int main() {
    cout << "Vertical Order Traversal: standalone solution is ready.\n";
    return 0;
}

