#include <bits/stdc++.h>
using namespace std;

struct TreeNode {
    int val;
    TreeNode* left;
    TreeNode* right;
    TreeNode(int value = 0, TreeNode* leftNode = nullptr, TreeNode* rightNode = nullptr)
        : val(value), left(leftNode), right(rightNode) {}
};

int widthOfBinaryTree(TreeNode* root) {
    if (!root) return 0;
    long long ans = 0;
    queue<pair<long long, TreeNode*>> q;
    q.push({0, root});

    while (!q.empty()) {
        int n = q.size();
        long long start = q.front().first;
        long long end = q.back().first;

        for (int i = 0; i < n; i++) {
            auto p = q.front();
            q.pop();

            long long index = p.first - start;
            TreeNode* curr = p.second;

            if (curr->left) q.push({2 * index + 1, curr->left});
            if (curr->right) q.push({2 * index + 2, curr->right});
        }

        ans = max(ans, end - start + 1);
    }

    return (int)ans;
}

