print-all-the-nodes-at-a-distance-of-k-i.code:
#include <bits/stdc++.h>
using namespace std;

struct TreeNode {
    int val;
    TreeNode* left;
    TreeNode* right;
    TreeNode(int value = 0, TreeNode* leftNode = nullptr, TreeNode* rightNode = nullptr)
        : val(value), left(leftNode), right(rightNode) {}
};

vector<int> distanceK(TreeNode* root, TreeNode* target, int k) {
    vector<int> ans;
    unordered_map<int, TreeNode*> parent;
    queue<TreeNode*> q;
    q.push(root);

    while (!q.empty()) {
        int si = q.size();
        for (int i = 0; i < si; i++) {
            auto top = q.front();
            q.pop();

            if (top->left) {
                parent[top->left->val] = top;
                q.push(top->left);
            }

            if (top->right) {
                parent[top->right->val] = top;
                q.push(top->right);
            }
        }
    }

    unordered_map<int, int> visited;
    q.push(target);
    while (k-- && !q.empty()) {
        int size = q.size();

        for (int i = 0; i < size; i++) {
            auto top = q.front();
            q.pop();

            visited[top->val] = 1;

            if (top->left && !visited[top->left->val]) {
                q.push(top->left);
            }

            if (top->right && !visited[top->right->val]) {
                q.push(top->right);
            }

            if (parent[top->val] && !visited[parent[top->val]->val]) {
                q.push(parent[top->val]);
            }
        }
    }

    while (!q.empty()) {
        ans.push_back(q.front()->val);
        q.pop();
    }
    return ans;
}

int main() {
    cout << "Nodes at Distance K: standalone solution is ready.\n";
    return 0;
}

minimum-time-taken-to-burn-the-binary-tr.code:
#include <bits/stdc++.h>
using namespace std;

struct TreeNode {
    int val;
    TreeNode* left;
    TreeNode* right;
    TreeNode(int value) : val(value), left(nullptr), right(nullptr) {}
};

int burnTime(TreeNode* root, int startValue) {
    unordered_map<TreeNode*, TreeNode*> parent;
    queue<TreeNode*> nodes;
    nodes.push(root);
    TreeNode* start = nullptr;
    while (!nodes.empty()) {
        TreeNode* node = nodes.front();
        nodes.pop();
        if (node->val == startValue) start = node;
        if (node->left) parent[node->left] = node, nodes.push(node->left);
        if (node->right) parent[node->right] = node, nodes.push(node->right);
    }
    unordered_set<TreeNode*> burned;
    nodes.push(start);
    burned.insert(start);
    int time = -1;
    while (!nodes.empty()) {
        int levelSize = nodes.size();
        ++time;
        while (levelSize--) {
            TreeNode* node = nodes.front();
            nodes.pop();
            for (TreeNode* next : {node->left, node->right, parent[node]}) {
                if (next && burned.insert(next).second) nodes.push(next);
            }
        }
    }
    return time;
}

int main() {
    TreeNode* root = new TreeNode(1);
    root->left = new TreeNode(2);
    root->right = new TreeNode(3);
    root->left->left = new TreeNode(4);
    cout << burnTime(root, 2) << "\n";
    return 0;
}

