    TreeNode* construct (vector<int>&pre, int&index, int upper) {

        if(index >= pre.size()) {return NULL ;}

        if(pre[index] < upper) {

            TreeNode* curr = new TreeNode(pre[index++]) ;
            curr -> left = construct(pre, index, curr -> val) ;

            curr -> right = construct(pre, index, upper) ;
            return curr ;
        }
        else{
            return NULL ;
        }

    }
};

