#include <bits/stdc++.h>
using namespace std;

struct TreeNode {
    int val;
    TreeNode* left;
    TreeNode* right;
    TreeNode(int value) : val(value), left(nullptr), right(nullptr) {}
};

pair<TreeNode*, TreeNode*> predecessorSuccessor(TreeNode* root, int key) {
    TreeNode* predecessor = nullptr;
    TreeNode* successor = nullptr;
    while (root) {
        if (root->val < key) {
            predecessor = root;
            root = root->right;
        } else if (root->val > key) {
            successor = root;
            root = root->left;
        } else {
            TreeNode* node = root->left;
            while (node) {
                predecessor = node;
                node = node->right;
            }
            node = root->right;
            while (node) {
                successor = node;
                node = node->left;
            }
            break;
        }
    }
    return {predecessor, successor};
}

int main() {
    TreeNode* root = new TreeNode(4);
    root->left = new TreeNode(2);
    root->right = new TreeNode(6);
    root->left->right = new TreeNode(3);
    root->right->left = new TreeNode(5);
    auto answer = predecessorSuccessor(root, 4);
    cout << answer.first->val << " " << answer.second->val << "\n";
    return 0;
}

