string classify(const Graph& graph) {
    bool weighted = false;
    for (const auto& edges : graph.adjacency) {
        for (const auto& edge : edges) weighted = weighted || edge.second != 1;
    }
    return string(graph.directed ? "directed" : "undirected") + (weighted ? " weighted" : " unweighted");
}

