#include <bits/stdc++.h>
using namespace std;
int orangesRotting(vector<vector<int>>& grid) {
    int ans = -1, fresh = 0, m = grid.size(), n = grid[0].size();
    queue<pair<int, int>> q;

    for(int i = 0; i < m; i++) {
        for(int j = 0; j < n; j++) {
            if(grid[i][j] == 2) {
                q.push({i, j});
            }
            if(grid[i][j] == 1) {
                fresh++;
            }
        }
    }

    if(fresh == 0) {
        return 0;
    }

    vector<int> dr = {-1, 1, 0, 0};
    vector<int> dc = {0, 0, -1, 1};

    while(!q.empty()) {
        int k = q.size();
        while(k--) {
            auto p = q.front();
            q.pop();
            int x = p.first, y = p.second;

            for(int i = 0; i < 4; i++) {
                int nx = x + dr[i], ny = y + dc[i];
                if(nx >= 0 && nx < m && ny >= 0 && ny < n && grid[nx][ny] == 1) {
                    grid[nx][ny] = 2;
                    q.push({nx, ny});
                    fresh--;
                }
            }
        }
        ans++;
    }

    return (fresh > 0) ? -1 : ans;
}

int main() {
    std::cout << "Rotting Oranges: standalone solution is ready.\n";
    return 0;
}

