#include <bits/stdc++.h>
using namespace std;

vector<int> topologicalSort(int vertices, const vector<pair<int, int>>& edges) {
    vector<vector<int>> graph(vertices);
    vector<int> indegree(vertices, 0);
    for (const auto& edge : edges) {
        int from = edge.first;
        int to = edge.second;
        graph[from].push_back(to);
        ++indegree[to];
    }
    priority_queue<int, vector<int>, greater<int>> ready;
    for (int node = 0; node < vertices; ++node) if (indegree[node] == 0) ready.push(node);
    vector<int> order;
    while (!ready.empty()) {
        int node = ready.top();
        ready.pop();
        order.push_back(node);
        for (int next : graph[node]) if (--indegree[next] == 0) ready.push(next);
    }
    return order.size() == (size_t)vertices ? order : vector<int>{};
}

int main() {
    for (int node : topologicalSort(6, {{5,2},{5,0},{4,0},{4,1},{2,3},{3,1}})) cout << node << " ";
