#include <bits/stdc++.h>
using namespace std;
bool isCyclic(int V, vector<int> adj[]) {
    vector<int> indeg(V, 0);

    for (int i = 0; i < V; i++) {
        for (auto it : adj[i]) {
            indeg[it]++;
        }
    }

    queue<int> q;

    for (int i = 0; i < V; i++) {
        if (indeg[i] == 0) {
            q.push(i);
        }
    }

    int cnt = 0;

    while (!q.empty()) {
        int node = q.front();
        q.pop();
        cnt++;

        for (auto i : adj[node]) {
            indeg[i]--;
            if (indeg[i] == 0) {
                q.push(i);
            }
        }
    }

    return !(cnt == V);
}

