bool dfsCycle(int node, const vector<vector<int>>& graph, vector<int>& visited, vector<int>& active) {
    visited[node] = active[node] = 1;
    for (int next : graph[node]) {
        if (!visited[next] && dfsCycle(next, graph, visited, active)) return true;
        if (active[next]) return true;
    }
    active[node] = 0;
    return false;
}

bool hasDirectedCycle(const vector<vector<int>>& graph) {
    vector<int> visited(graph.size(), 0), active(graph.size(), 0);
    for (int node = 0; node < (int)graph.size(); ++node) {
        if (!visited[node] && dfsCycle(node, graph, visited, active)) return true;
    }
    return false;
}

