bool hasDirectedCycleKahn(const vector<vector<int>>& graph) {
    vector<int> indegree(graph.size(), 0);
    for (const auto& edges : graph) for (int next : edges) ++indegree[next];
    queue<int> ready;
    for (int node = 0; node < (int)graph.size(); ++node) if (indegree[node] == 0) ready.push(node);
    int processed = 0;
    while (!ready.empty()) {
        int node = ready.front();
        ready.pop();
        ++processed;
        for (int next : graph[node]) if (--indegree[next] == 0) ready.push(next);
