#include <bits/stdc++.h>
using namespace std;

int countShortestPaths(int vertices, const vector<array<int, 3>>& roads) {
    const long long infinity = numeric_limits<long long>::max() / 4;
    const int mod = 1000000007;
    vector<vector<pair<int, int>>> graph(vertices);
    for (auto road : roads) {
        graph[road[0]].push_back({road[1], road[2]});
        graph[road[1]].push_back({road[0], road[2]});
    }
    vector<long long> distance(vertices, infinity);
    vector<int> ways(vertices, 0);
    priority_queue<pair<long long, int>, vector<pair<long long, int>>, greater<pair<long long, int>>> queue;
    distance[0] = 0;
    ways[0] = 1;
    queue.push({0, 0});
    while (!queue.empty()) {
        pair<long long, int> current = queue.top();
        queue.pop();
        long long currentDistance = current.first;
        int node = current.second;
        if (currentDistance != distance[node]) continue;
        for (const auto& edge : graph[node]) {
            int next = edge.first;
            int weight = edge.second;
            long long candidate = currentDistance + weight;
            if (candidate < distance[next]) {
                distance[next] = candidate;
                ways[next] = ways[node];
                queue.push({candidate, next});
            } else if (candidate == distance[next]) {
                ways[next] = (ways[next] + ways[node]) % mod;
            }
        }
    }
    return ways.back();
}

int main() {
    cout << countShortestPaths(4, {{0,1,1},{0,2,1},{1,3,1},{2,3,1}}) << "\n";
    return 0;
}

