#include <bits/stdc++.h>
using namespace std;
class DisjointSet {
    vector<int> parent, size;

public:
    DisjointSet(int n) {
        parent.resize(n);
        size.resize(n, 1);
        for (int i = 0; i < n; i++)
            parent[i] = i;
    }

    int findUPar(int node) {
        if (parent[node] == node)
            return node;
        return parent[node] = findUPar(parent[node]);
    }

    void unionBySize(int u, int v) {
        int uP = findUPar(u), vP = findUPar(v);
        int uPSize = size[uP], vPSize = size[vP];
        if (uPSize > vPSize) {
            parent[vP] = uP;
            size[uP] += vPSize;
        } else {
            parent[uP] = vP;
            size[vP] += uPSize;
        }
    }

    int disconnected(int n) {
        int cnt = 0;
        for (int i = 0; i < n; i++) {
            if (parent[i] == i)
                cnt++;
        }
        return cnt;
    }
};

int makeConnected(int n, vector<vector<int>>& connections) {
    if (n - 1 > connections.size())
        return -1;

    DisjointSet djs(n);
    for (auto c : connections) {
        int u = c[0], v = c[1];
        if (djs.findUPar(u) != djs.findUPar(v))
            djs.unionBySize(u, v);
    }

    int ans = djs.disconnected(n);
    return ans - 1;
}

int main() {
    std::cout << "Network Connectivity (DSU): standalone solution is ready.\n";
    return 0;
}

