#include <bits/stdc++.h>
using namespace std;

class DisjointSet {
    vector<int> size, parent ;
public:
    DisjointSet (int n) {
        size.resize(n  , 1) ; parent.resize(n) ;
        for(int i =0; i < n ; i++){parent[i] = i ;}
    }

    int findPar (int node) {

        if(parent[node] == node) {
            return node ;
        }

        return parent[node] = findPar(parent[node]) ;
    }

    void union_by_size(int u , int v) {
        int pu = findPar(u) , pv = findPar(v) ;

        if(pu == pv) {
            return ;
        }

       if(size[pu] < size[pv]){
            parent[pu] = pv ;
            size[pv] += size[pu] ;
       }
       else{

            parent[pv] = pu ;
            size[pu] += size[pv] ;
       }
    }

    bool isSameComponent (int u, int v) {
        return (findPar(u) == findPar(v)) ;
    }
};

class Solution{
public:
    vector<vector<string>> mergeDetails(vector<vector<string>> &details){

        int n = details.size() ;

        DisjointSet ds (n) ;

        unordered_map<string, int> mp ;
        for(int i =0; i < n ; i++){
            for(int j = 1 ; j < details[i].size() ; j++){

                string mail = details[i][j] ;
                if(mp.count(mail)) {

                    ds.union_by_size(i , mp[mail]) ;
                }
                else{
                    mp[mail] = i ;
                }
            }
        }

        vector<string> accounts[n] ;
        for(auto it : mp){
            string mail = it.first ; int index =it.second;
            accounts[ds.findPar(index)].push_back(mail) ;
        }

        vector<vector<string>> ans ;
        for(int i =0 ;i < n ; i++) {
            if(accounts[i].size() != 0) {

                sort(accounts[i].begin() , accounts[i].end()) ;
                vector<string> curr ; curr.push_back(details[i][0]) ;
                for(auto it: accounts[i]) {
                    curr.push_back(it) ;
                }
                ans.push_back(curr) ;
            }
        }

        sort(ans.begin() , ans.end()) ; return ans ;
    }
};

