#include <bits/stdc++.h>
using namespace std;

int swimInWater(const vector<vector<int>>& grid) {
    int size = grid.size();
    vector<vector<int>> best(size, vector<int>(size, numeric_limits<int>::max()));
    priority_queue<array<int, 3>, vector<array<int, 3>>, greater<array<int, 3>>> queue;
    best[0][0] = grid[0][0];
    queue.push({best[0][0], 0, 0});
    const int directions[5] = {1, 0, -1, 0, 1};
    while (!queue.empty()) {
        array<int, 3> current = queue.top();
        queue.pop();
        int time = current[0];
        int row = current[1];
        int col = current[2];
        if (row == size - 1 && col == size - 1) return time;
        if (time != best[row][col]) continue;
        for (int direction = 0; direction < 4; ++direction) {
            int nextRow = row + directions[direction];
            int nextCol = col + directions[direction + 1];
            if (nextRow < 0 || nextRow >= size || nextCol < 0 || nextCol >= size) continue;
            int candidate = max(time, grid[nextRow][nextCol]);
            if (candidate < best[nextRow][nextCol]) {
                best[nextRow][nextCol] = candidate;
                queue.push({candidate, nextRow, nextCol});
            }
        }
    }
    return -1;
}

int main() {
    cout << swimInWater({{0, 2}, {1, 3}}) << "\n";
    return 0;
}

