    if (i - 1 >= 0)
        s1 = fmemo(i - 1, h, dp) + abs(h[i - 1] - h[i]);
    if (i - 2 >= 0)
        s2 = fmemo(i - 2, h, dp) + abs(h[i - 2] - h[i]);

