int fmemo(int n, int prev, vector<vector<int>>& points, vector<vector<int>>& memo) {
    if (n < 0)
        return 0;

    if (prev != -1 && memo[n][prev] != -1) {
        return memo[n][prev];
    }

    int ans = 0;
    for (int i = 0; i < 3; i++) {
        if (i != prev) {
            int temp = points[n][i] + fmemo(n - 1, i, points, memo);
            ans = max(ans, temp);
        }
    }

    if (prev != -1) {
        memo[n][prev] = ans;
    }

    return ans;
}

