#include <bits/stdc++.h>
using namespace std;
int fmemo(int i, int j, vector<vector<int>>& grid, vector<vector<int>>& dp) {
    if (i < 0 || j < 0)
        return 0;

    if (dp[i][j] != -1)
        return dp[i][j];

    if (grid[i][j] == 1)
        return dp[i][j] = 0;

    int top = fmemo(i - 1, j, grid, dp);
    int left = fmemo(i, j - 1, grid, dp);
    return dp[i][j] = top + left;
}

int ftab(int m, int n, vector<vector<int>>& grid){
    vector<vector<int>> dp(m,vector<int>(n));
    for(int i=0; i<m; i++){
        for(int j=0; j<n; j++){
            if(i==0 && j==0){
                dp[i][j] = 1;
                continue;
            }
            if(grid[i][j]==1){
                dp[i][j] = 0;
                continue;
            }
            int top = 0, left = 0;
            if(i-1>=0) top = dp[i-1][j];
            if(j-1>=0) left = dp[i][j-1];
            dp[i][j] = top+left;
        }
    }
    return dp[m-1][n-1];
}

int fopt(int m, int n, vector<vector<int>>& grid){
    vector<int> prev(n);
    for(int i=0; i<m; i++){
        vector<int> curr(n);
        for(int j=0; j<n; j++){
            if(grid[i][j]==1){
                curr[j]=0;
                continue;
            }
            if(i==0 && j==0){
                curr[j]=1;
                continue;
            }
            int top = 0, left = 0;
            if(i-1>=0) top = prev[j];
            if(j-1>=0) left = curr[j-1];
            curr[j] = top+left;
        }
        prev = curr;
