    if (obstacleGrid[0][0] == 1 || obstacleGrid[m - 1][n - 1] == 1)
        return 0;

    vector<vector<int>> dp(m, vector<int>(n, -1));
    return fmemo(m - 1, n - 1, obstacleGrid, dp);
}

