            if(i==0){
                if(amt%coins[i]==0) dp[i][amt] =  amt/coins[i];
                else dp[i][amt] = 1e9;
                continue;
            }
            int take = 1e9;
            if(coins[i]<=amt) take = 1+dp[i][amt-coins[i]];
            int notake = dp[i-1][amt];
            dp[i][amt] = min(take,notake);
        }
    }
    return dp[n-1][amount];
}

