#include <bits/stdc++.h>
using namespace std;

class Solution {
public:

    bool isAllStars(string &S1, int i) {

        for (int j = 0; j <= i; j++) {
            if (S1[j] != '*')
                return false;
        }
        return true;
    }

    bool wildcardMatchingUtil(string &S1, string &S2, int i, int j, vector<vector<int>> &dp) {

        if (i < 0 && j < 0)
            return true;

        if (i < 0 && j >= 0)
            return false;

        if (j < 0 && i >= 0)
            return isAllStars(S1, i);

        if (dp[i][j] != -1)
            return dp[i][j];

        if (S1[i] == S2[j] || S1[i] == '?')
            return dp[i][j] = wildcardMatchingUtil(S1, S2, i - 1, j - 1, dp);

        if (S1[i] == '*')
            return dp[i][j] = wildcardMatchingUtil(S1, S2, i - 1, j, dp) ||
                               wildcardMatchingUtil(S1, S2, i, j - 1, dp);

        return dp[i][j] = false;
    }

    bool wildcardMatching(string &S1, string &S2) {
        int n = S1.size();
        int m = S2.size();

        vector<vector<int>> dp(n, vector<int>(m, -1));

        return wildcardMatchingUtil(S1, S2, n - 1, m - 1, dp);
    }
};

int main() {

    string S1 = "ab*cd";
    string S2 = "abdefcd";

    Solution obj;

    if (obj.wildcardMatching(S1, S2))
        cout << "String S1 and S2 do match";
    else
        cout << "String S1 and S2 do not match";

    return 0;
}

#include <bits/stdc++.h>
using namespace std;
bool allStars(int i, string& p) {
    for (int j = i; j >= 0; j--) {
        if (p[j] != '*') return false;
    }
    return true;
}

int fmemo(int i, int j, string& s, string& p, vector<vector<int>>& dp) {
    if (i < 0 && j < 0) return true;
    if (j < 0 && i >= 0) return false;
    if (i < 0 && j >= 0) {
        if (allStars(j, p)) return true;
        return false;
    }

    if (dp[i][j] != -1) return dp[i][j];

    if (s[i] == p[j] || p[j] == '?')
        return dp[i][j] = fmemo(i - 1, j - 1, s, p, dp);
    else {
        if (p[j] == '*')
            return dp[i][j] = (fmemo(i - 1, j, s, p, dp) || fmemo(i, j - 1, s, p, dp));
        return dp[i][j] = false;
    }
}

bool isMatch(string s, string p) {
    int n = s.size(), m = p.size();
    vector<vector<int>> dp(n, vector<int>(m, -1));
    return fmemo(n - 1, m - 1, s, p, dp);
}

