#include <bits/stdc++.h>
using namespace std;

bool isPredecessor(const string& shorter, const string& longer) {
    if (longer.size() != shorter.size() + 1) return false;
    size_t left = 0, right = 0;
    while (right < longer.size()) {
        if (left < shorter.size() && shorter[left] == longer[right]) ++left;
        ++right;
    }
    return left == shorter.size();
}

int longestStringChain(vector<string> words) {
    sort(words.begin(), words.end(), [](const string& left, const string& right) {
        return left.size() < right.size();
    });
    vector<int> best(words.size(), 1);
    int answer = 0;
    for (int index = 0; index < (int)words.size(); ++index) {
        for (int previous = 0; previous < index; ++previous) {
            if (isPredecessor(words[previous], words[index])) {
                best[index] = max(best[index], best[previous] + 1);
            }
        }
        answer = max(answer, best[index]);
    }
    return answer;
}

int main() {
    cout << longestStringChain({"a", "b", "ba", "bca", "bda", "bdca"}) << "\n";
    return 0;
