#define ll long long
const int mod = 1000000007;

int f(int i, int j, int isTrue, string &exp) {

    if (i > j) return 0;

    if (i == j) {
        if (isTrue == 1) return exp[i] == 'T' ? 1 : 0;
        else return exp[i] == 'F' ? 1 : 0;
    }

    ll ways = 0;

    for (int ind = i + 1; ind <= j - 1; ind += 2) {

        ll lT = f(i, ind - 1, 1, exp);
        ll lF = f(i, ind - 1, 0, exp);
        ll rT = f(ind + 1, j, 1, exp);
        ll rF = f(ind + 1, j, 0, exp);

        if (exp[ind] == '&') {
            if (isTrue) ways = (ways + (lT * rT) % mod) % mod;
            else ways = (ways + (lF * rT) % mod + (lT * rF) % mod + (lF * rF) % mod) % mod;
        }
        else if (exp[ind] == '|') {
            if (isTrue) ways = (ways + (lF * rT) % mod + (lT * rF) % mod + (lT * rT) % mod) % mod;
            else ways = (ways + (lF * rF) % mod) % mod;
        }
        else {
            if (isTrue) ways = (ways + (lF * rT) % mod + (lT * rF) % mod) % mod;
            else ways = (ways + (lF * rF) % mod + (lT * rT) % mod) % mod;
        }
    }
    return ways;
}

int evaluateExp(string &exp) {
    int n = exp.size();
    return f(0, n - 1, 1, exp);
}

int main() {

    string exp = "F|T^F";

    int ways = evaluateExp(exp);

    cout << "The total number of ways: " << ways << "\n";

    return 0;
}

#include <bits/stdc++.h>
using namespace std;

#define ll long long
const int mod = 1000000007;

int f(int i, int j, int isTrue, string &exp, vector<vector<vector<ll>>> &dp) {

    if (i > j) return 0;

    if (i == j) {
        if (isTrue == 1) return exp[i] == 'T' ? 1 : 0;
        else return exp[i] == 'F' ? 1 : 0;
    }

    if (dp[i][j][isTrue] != -1) return dp[i][j][isTrue];

    ll ways = 0;

    for (int ind = i + 1; ind <= j - 1; ind += 2) {

        ll lT = f(i, ind - 1, 1, exp, dp);
        ll lF = f(i, ind - 1, 0, exp, dp);
        ll rT = f(ind + 1, j, 1, exp, dp);
        ll rF = f(ind + 1, j, 0, exp, dp);

        if (exp[ind] == '&') {
            if (isTrue) ways = (ways + (lT * rT) % mod) % mod;
            else ways = (ways + (lF * rT) % mod + (lT * rF) % mod + (lF * rF) % mod) % mod;
        }
        else if (exp[ind] == '|') {
            if (isTrue) ways = (ways + (lF * rT) % mod + (lT * rF) % mod + (lT * rT) % mod) % mod;
            else ways = (ways + (lF * rF) % mod) % mod;
        }
        else {
            if (isTrue) ways = (ways + (lF * rT) % mod + (lT * rF) % mod) % mod;
            else ways = (ways + (lF * rF) % mod + (lT * rT) % mod) % mod;
        }
    }

    return dp[i][j][isTrue] = ways;
}

int evaluateExp(string &exp) {
    int n = exp.size();
    vector<vector<vector<ll>>> dp(n, vector<vector<ll>>(n, vector<ll>(2, -1)));
    return f(0, n - 1, 1, exp, dp);
}

int main() {
    string exp = "F|T^F";

    int ways = evaluateExp(exp);

    cout << "The total number of ways: " << ways << "\n";

    return 0;
}

#include <bits/stdc++.h>
using namespace std;

long long trueWays(const string& expression) {
    const int mod = 1000000007;
    int operands = (expression.size() + 1) / 2;
    vector<vector<array<long long, 2>>> dp(operands, vector<array<long long, 2>>(operands, {0, 0}));
    for (int index = 0; index < operands; ++index) dp[index][index][expression[2 * index] == 'T'] = 1;
    for (int length = 2; length <= operands; ++length) {
        for (int left = 0; left + length <= operands; ++left) {
            int right = left + length - 1;
            for (int split = left; split < right; ++split) {
                char operation = expression[2 * split + 1];
                for (int a = 0; a < 2; ++a) {
                    for (int b = 0; b < 2; ++b) {
                        bool result = operation == '&' ? a && b : operation == '|' ? a || b : a != b;
                        dp[left][right][result] = (dp[left][right][result] + dp[left][split][a] * dp[split + 1][right][b]) % mod;
                    }
                }
            }
        }
    }
    return dp[0][operands - 1][1];
}

int main() {
    cout << trueWays("T|F&T^T") << "\n";
    return 0;
}

