#include <bits/stdc++.h>
using namespace std;
bool isPalindrome(int i, int j, string& s){
    while(i < j){
        if(s[i] != s[j]) return false;
        i++; j--;
    }
    return true;
}

int fmemo(int i, string& s, vector<int>& dp){
    if(i == s.size()) return 0;

    if(dp[i] != -1) return dp[i];

    int ans = 1e9;
    for(int j = i; j < s.size(); j++){
        if(isPalindrome(i, j, s)){
            int cost = 1 + fmemo(j + 1, s, dp);
            ans = min(ans, cost);
        }
    }
    return dp[i] = ans;
}

int minCut(string s) {
    int n = s.size();
    vector<int> dp(n, -1);
    return fmemo(0, s, dp) - 1;
}

int main() {
    std::cout << "Palindrome Partitioning II: standalone solution is ready.\n";
    return 0;
}

