#include <bits/stdc++.h>
using namespace std;
int fmemo(int i, int k, vector<int>& arr, vector<int>& dp){
    if(i == arr.size()) return 0;

    if(dp[i] != -1) return dp[i];

    int n = arr.size();
    int maxi = 0, ans = 0;
    for(int j = i; j < min(i + k, n); j++){
        maxi = max(maxi, arr[j]);
        int maxSum = maxi * (j - i + 1) + fmemo(j + 1, k, arr, dp);
        ans = max(ans, maxSum);
    }
    return dp[i] = ans;
}

int maxSumAfterPartitioning(vector<int>& arr, int k) {
    int n = arr.size();
    vector<int> dp(n, -1);
    return fmemo(0, k, arr, dp);
}

int main() {
    std::cout << "Partition Array for Max Sum: standalone solution is ready.\n";
    return 0;
}

