#include <bits/stdc++.h>
using namespace std;
class TrieNode {
public:
    TrieNode* children[26];
    bool end;

    TrieNode() {
        this->end = false;
        for (int i = 0; i < 26; i++) {
            this->children[i] = NULL;
        }
    }
};

class Trie {
public:
    TrieNode* root;

    Trie() {
        root = new TrieNode();
    }

    void insert(string& word) {
        TrieNode* curr = root;
        int n = word.size();
        for (int i = 0; i < n; i++) {
            int key = word[i] - 'a';
            if (curr->children[key] == NULL) {
                curr->children[key] = new TrieNode();
            }
            curr = curr->children[key];
        }
        curr->end = true;
    }

    bool isvalid(string& word) {
        TrieNode* curr = root;
        int n = word.size();
        for (int i = 0; i < n; i++) {
            int key = word[i] - 'a';
            if (curr->children[key] == NULL || curr->children[key]->end == false) {
                return false;
            }
            curr = curr->children[key];
        }
        return curr != NULL && curr->end;
    }
};

string completeString(int n, vector<string>& a) {

    Trie tr;

    for (auto it : a) {
        tr.insert(it);
    }

    string ans = "";

    for (auto it : a) {
        if (tr.isvalid(it)) {
            if (ans.size() < it.size())
                ans = it;
            else if (ans.size() == it.size() && it < ans)
                ans = it;
        }
    }
    if (ans.size() == 0)
        return "None";
    return ans;

}

int main() {
    cout << "Complete String: standalone solution is ready.\n";
    return 0;
}

