#include <bits/stdc++.h>
using namespace std;

struct BitNode {
    BitNode* next[2] = {nullptr, nullptr};
};

class BinaryTrie {
    BitNode* root = new BitNode();
public:
    void insert(int value) {
        BitNode* node = root;
        for (int bit = 30; bit >= 0; --bit) {
            int current = (value >> bit) & 1;
            if (!node->next[current]) node->next[current] = new BitNode();
            node = node->next[current];
        }
    }
    int maximumXor(int value) const {
        BitNode* node = root;
        int answer = 0;
        for (int bit = 30; bit >= 0; --bit) {
            int current = (value >> bit) & 1;
            if (node->next[1 - current]) {
                answer |= 1 << bit;
                node = node->next[1 - current];
            } else {
                node = node->next[current];
            }
        }
        return answer;
    }
};

vector<int> maximizeXor(vector<int> values, const vector<pair<int, int>>& queries) {
    sort(values.begin(), values.end());
    vector<array<int, 3>> ordered;
    for (int index = 0; index < (int)queries.size(); ++index) {
        ordered.push_back({queries[index].second, queries[index].first, index});
    }
    sort(ordered.begin(), ordered.end());
    BinaryTrie trie;
    vector<int> answer(queries.size(), -1);
    int index = 0;
    for (const auto& query : ordered) {
        int limit = query[0];
        int value = query[1];
        int queryIndex = query[2];
        while (index < (int)values.size() && values[index] <= limit) trie.insert(values[index++]);
        if (index > 0) answer[queryIndex] = trie.maximumXor(value);
    }
    return answer;
}

int main() {
    for (int answer : maximizeXor({0, 1, 2, 3, 4}, {{3, 1}, {1, 3}, {5, 6}})) cout << answer << " ";
    cout << "\n";
    return 0;
}
